// ===========================================================
// SEO — 共通SEOヘッド管理（強化版）
// 各ページで <Seo title="..." description="..." /> と使う
// 対応: OG / Twitter Card / JSON-LD (Article, Breadcrumb, Course, FAQ) / hreflang
// ===========================================================

import { useEffect, useRef } from 'react'

interface SeoProps {
  title?: string
  description?: string
  path?: string
  image?: string
  type?: 'website' | 'article'
  noindex?: boolean
  /** 記事の公開日（article 型の場合） */
  publishedTime?: string
  /** 記事の更新日 */
  modifiedTime?: string
  /** 著者名 */
  author?: string
  /** タグ（カンマ区切り文字列） */
  keywords?: string
  /** パンくずリスト */
  breadcrumbs?: { name: string; path: string }[]
  /** JSON-LD Article 本文サマリ（description より詳しい場合） */
  articleBody?: string
}

const SITE_NAME = 'SAP パンダ先生 NAVI'
const SITE_NAME_ALT = 'SAP Panda Sensei'
const BASE_URL = 'https://sap-panda.com'
const TWITTER_HANDLE = '@sap_panda'
const DEFAULT_DESC = 'SAP のしくみを、パンダ先生がやさしく解説。財務・購買・販売・生産・人事 — むずかしい SAP を、たろうくんと一緒に「わからない…！」から「なるほど！」へ。'
const DEFAULT_KEYWORDS = 'SAP,S/4HANA,ERP,会計,ABAP,FI,CO,MM,SD,学習,パンダ先生,ナレッジ,SAP資格,SAPコンサル'

/** JSON-LD スクリプトを head に追加/更新 */
function setJsonLd(id: string, data: Record<string, unknown>) {
  const existing = document.getElementById(id) as HTMLScriptElement | null
  if (existing) existing.remove()
  const script = document.createElement('script')
  script.id = id
  script.type = 'application/ld+json'
  script.textContent = JSON.stringify({
    '@context': 'https://schema.org',
    ...data,
  })
  document.head.appendChild(script)
}

/** 指定した属性の meta タグを set/remove */
function setMeta(name: string, content: string, property = false) {
  const attr = property ? 'property' : 'name'
  let el = document.querySelector(`meta[${attr}="${name}"]`) as HTMLMetaElement | null
  if (!el) {
    el = document.createElement('meta')
    el.setAttribute(attr, name)
    document.head.appendChild(el)
  }
  el.content = content
}

function removeMeta(name: string, property = false) {
  const attr = property ? 'property' : 'name'
  document.querySelector(`meta[${attr}="${name}"]`)?.remove()
}

export default function Seo({
  title, description, path, image, type = 'website',
  noindex, publishedTime, modifiedTime, author, keywords,
  breadcrumbs, articleBody,
}: SeoProps) {
  const pageTitle = title ? `${title} | ${SITE_NAME}` : SITE_NAME
  const desc = description || DEFAULT_DESC
  const kw = keywords || DEFAULT_KEYWORDS
  const url = path ? `${BASE_URL}${path}` : BASE_URL
  const img = image || `${BASE_URL}/panda-sensei.png`

  // ref で安定参照 — deps 減らして不要な再実行を防止
  const prev = useRef({ title: '', desc: '', url: '', img: '' })

  useEffect(() => {
    // ---- タイトル ----
    document.title = pageTitle

    // ---- Basic meta ----
    setMeta('description', desc)
    setMeta('keywords', kw)

    // ---- Robots ----
    if (noindex) {
      setMeta('robots', 'noindex,nofollow')
    } else {
      removeMeta('robots')
    }

    // ---- Canonical ----
    let canonical = document.querySelector('link[rel="canonical"]') as HTMLLinkElement | null
    if (!canonical) {
      canonical = document.createElement('link')
      canonical.rel = 'canonical'
      document.head.appendChild(canonical)
    }
    canonical.href = url

    // ---- hreflang ----
    const ensureHreflang = (hrefLang: string, href: string) => {
      const sel = `link[rel="alternate"][hreflang="${hrefLang}"]`
      let el = document.querySelector(sel) as HTMLLinkElement | null
      if (!el) {
        el = document.createElement('link')
        el.rel = 'alternate'
        el.hreflang = hrefLang
        document.head.appendChild(el)
      }
      el.href = href
    }
    ensureHreflang('ja', url)
    ensureHreflang('x-default', url)

    // ---- OG ----
    setMeta('og:title', pageTitle, true)
    setMeta('og:description', desc, true)
    setMeta('og:url', url, true)
    setMeta('og:type', type, true)
    setMeta('og:site_name', SITE_NAME, true)
    setMeta('og:image', img, true)
    setMeta('og:image:width', '1200', true)
    setMeta('og:image:height', '630', true)
    setMeta('og:locale', 'ja_JP', true)

    // ---- Article OG 拡張 ----
    if (type === 'article') {
      if (publishedTime) setMeta('article:published_time', publishedTime, true)
      if (modifiedTime) setMeta('article:modified_time', modifiedTime, true)
      if (author) setMeta('article:author', author, true)
    }

    // ---- Twitter Card ----
    setMeta('twitter:card', 'summary_large_image')
    setMeta('twitter:site', TWITTER_HANDLE)
    setMeta('twitter:title', pageTitle)
    setMeta('twitter:description', desc)
    setMeta('twitter:image', img)

    // ---- JSON-LD: WebSite ----
    setJsonLd('seo-website-ld', {
      '@type': 'WebSite',
      name: SITE_NAME,
      alternateName: SITE_NAME_ALT,
      url: BASE_URL,
      description: DEFAULT_DESC,
      potentialAction: {
        '@type': 'SearchAction',
        target: { '@type': 'EntryPoint', urlTemplate: `${BASE_URL}/search?q={search_term_string}` },
        'query-input': 'required name=search_term_string',
      },
    })

    // ---- JSON-LD: Organization ----
    setJsonLd('seo-org-ld', {
      '@type': 'Organization',
      name: SITE_NAME,
      alternateName: SITE_NAME_ALT,
      url: BASE_URL,
      logo: `${BASE_URL}/panda-sensei.png`,
      description: DEFAULT_DESC,
    })

    // ---- JSON-LD: BreadcrumbList ----
    if (breadcrumbs && breadcrumbs.length > 0) {
      setJsonLd('seo-breadcrumb-ld', {
        '@type': 'BreadcrumbList',
        itemListElement: breadcrumbs.map((b, i) => ({
          '@type': 'ListItem',
          position: i + 1,
          name: b.name,
          item: `${BASE_URL}${b.path}`,
        })),
      })
    } else {
      document.getElementById('seo-breadcrumb-ld')?.remove()
    }

    // ---- JSON-LD: Article (type === 'article' の場合) ----
    if (type === 'article' && title) {
      setJsonLd('seo-article-ld', {
        '@type': 'Article',
        headline: title,
        description: desc,
        image: img,
        author: author ? { '@type': 'Person', name: author } : { '@type': 'Organization', name: SITE_NAME },
        publisher: { '@type': 'Organization', name: SITE_NAME, logo: { '@type': 'ImageObject', url: `${BASE_URL}/panda-sensei.png` } },
        datePublished: publishedTime || new Date().toISOString(),
        dateModified: modifiedTime || publishedTime || new Date().toISOString(),
        mainEntityOfPage: { '@type': 'WebPage', '@id': url },
        ...(articleBody ? { articleBody } : {}),
      })
    } else {
      document.getElementById('seo-article-ld')?.remove()
    }

    prev.current = { title: pageTitle, desc, url, img }
  }, [pageTitle, desc, url, img, type, noindex, kw, publishedTime, modifiedTime, author, breadcrumbs, articleBody])

  return null
}
